import React from 'react';
import '../styles/global.css'; // Import the CSS

const Home = () => {
  return (
    <div className="main-container">
      {/* Hero Section */}
      <section className="hero-section">
        <img className="hero-image" src="/assets/hero.jpg" alt="Hero Plant" />
        <div className="hero-text">
          <h1>Welcome to NatureNest 🌿</h1>
          <p>Your one-stop online plant nursery. Discover, shop, and learn plant care from the experts.</p>
          <button>Shop Now</button>
        </div>
      </section>

      {/* About Us */}
      <section className="about-section">
        <h2>About Us</h2>
        <p>
          At <strong>NatureNest</strong>, we are passionate about nurturing a greener, healthier lifestyle...
          <br /><br />
          We collaborate with local nurseries...
          <br /><br />
          By choosing NatureNest, you're not just buying a plant—you're joining a movement...
        </p>
      </section>

      {/* Featured Plants */}
      <section className="featured-section">
        <h2>Featured Plants</h2>
        <div className="plant-grid">
          {[
            {
              name: 'Snake Plant',
              image: '/assets/plant1.jpg',
              desc: 'Low-maintenance air-purifier perfect for bedrooms and offices.',
            },
            {
              name: 'Aloe Vera',
              image: '/assets/plant2.jpg',
              desc: 'Medicinal plant with soothing gel—great for skin care and burns.',
            },
            {
              name: 'Peace Lily',
              image: '/assets/plant3.jpg',
              desc: 'Elegant white blooms and natural air-purifying qualities.',
            },
            {
              name: 'Spider Plant',
              image: '/assets/plant4.jpg',
              desc: 'Fast-growing with cascading leaves—ideal for hanging baskets.',
            },
          ].map((plant, i) => (
            <div className="plant-card" key={i}>
              <img src={plant.image} alt={plant.name} />
              <h3>{plant.name}</h3>
              <p>{plant.desc}</p>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

export default Home;
